1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	interface Item {
13	  type: string;
14	}
15	
16	interface QuoteStep {
17	  items: Item[];
18	}
19	
20	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
21	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
22	// that is only spuriously above a whole number.
23	const roundUpInMHPCOsFavor = (amount: number): number =>
24	  Math.ceil(Number(amount.toFixed(6)));
25	
26	const basePremiumForItem = (item: Item): number =>
27	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
28	
29	export const quote = (
30	  customer: unknown,
31	  step: QuoteStep,
32	  quoteIndex: number,
33	): number => {
34	  const basePremium = step.items.reduce(
35	    (sum, item) => sum + basePremiumForItem(item),
36	    0,
37	  );
38	  const withFirstInsurance = basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
39	  const total = withFirstInsurance + PROCESSING_FEE;
40	  return roundUpInMHPCOsFavor(total);
41	};
42	
43	export const claim = (...args: unknown[]): unknown => {
44	  return undefined; // Intentionally not implemented
45	};
